const configPage = $node['Lire paramètres'].json.results?.[0];
if (!configPage) throw new Error('Aucune configuration active trouvée dans Notion.');

const p = configPage.properties;
const config = {
  personnes: p['Personnes']?.number ?? 2,
  objectif: p['Objectif']?.select?.name ?? 'Perte de poids',
  calories: p['Calories cibles']?.number ?? 2200,
  budget: p['Budget hebdomadaire']?.number ?? 90,
  email: p['Email']?.email ?? 'jasonmarmignon@gmail.com',
  nouvelles_recettes_max: p['Nouvelles recettes max']?.number ?? 1,
  saison: p['Saison']?.select?.name ?? 'Automatique',
  jours: (p['Jours de cuisine']?.multi_select ?? []).map(x => x.name)
};

const recipes = ($json.results ?? []).map(page => {
  const r = page.properties;
  return {
    id: page.id,
    nom: r['Nom']?.title?.map(x => x.plain_text).join('') ?? '',
    type: r['Type']?.select?.name ?? '',
    saisons: (r['Saison']?.multi_select ?? []).map(x => x.name),
    calories: r['Calories par portion']?.number ?? null,
    proteines: r['Protéines (g)']?.number ?? null,
    note: r['Note']?.number ?? null,
    portions: r['Portions']?.number ?? 2,
    ingredients: r['Ingrédients']?.rich_text?.map(x => x.plain_text).join('') ?? '',
    preparation: r['Préparation']?.rich_text?.map(x => x.plain_text).join('') ?? ''
  };
}).filter(r => r.nom);

if (!recipes.length) throw new Error('Aucune recette validée trouvée dans Notion.');

const system = `Tu es le chef personnel de Jason. Compose un menu hebdomadaire simple et adapté à une perte de poids. Utilise uniquement les recettes existantes fournies. Évite poisson, quinoa, brocoli, épinards et choux de Bruxelles. Retourne uniquement le JSON demandé.`;
const user = `CONFIGURATION\n${JSON.stringify(config, null, 2)}\n\nRECETTES VALIDÉES\n${JSON.stringify(recipes, null, 2)}\n\nCrée un repas pour chaque jour configuré. Le nom de chaque recette doit correspondre exactement à un nom fourni. Fusionne les ingrédients dans une liste de courses classée par rayon.`;

return [{ json: { config, recipes, openai_body: {
  model: 'gpt-5-mini',
  input: [
    { role: 'system', content: [{ type: 'input_text', text: system }] },
    { role: 'user', content: [{ type: 'input_text', text: user }] }
  ],
  text: { format: {
    type: 'json_schema',
    name: 'weekly_menu',
    strict: true,
    schema: {
      type: 'object',
      additionalProperties: false,
      required: ['week_start','summary','meals','shopping','estimated_weekly_budget_eur','notes'],
      properties: {
        week_start: { type: 'string' },
        summary: { type: 'string' },
        meals: { type: 'array', items: { type: 'object', additionalProperties: false, required: ['day','recipe_name','is_new','reason'], properties: { day:{type:'string'}, recipe_name:{type:'string'}, is_new:{type:'boolean'}, reason:{type:'string'} } } },
        shopping: { type: 'object', additionalProperties: false, required: ['fruits_legumes','viandes_proteines','produits_frais','epicerie','surgeles','autres'], properties: { fruits_legumes:{type:'array',items:{type:'string'}}, viandes_proteines:{type:'array',items:{type:'string'}}, produits_frais:{type:'array',items:{type:'string'}}, epicerie:{type:'array',items:{type:'string'}}, surgeles:{type:'array',items:{type:'string'}}, autres:{type:'array',items:{type:'string'}} } },
        estimated_weekly_budget_eur: { type: 'number' },
        notes: { type: 'array', items: { type: 'string' } }
      }
    }
  } }
} } }];

const raw = $json.output_text ?? $json.output?.flatMap(o => o.content ?? []).find(c => c.type === 'output_text')?.text;
if (!raw) throw new Error('OpenAI n’a retourné aucun texte exploitable.');
let menu;
try { menu = JSON.parse(raw); } catch (e) { throw new Error('La réponse OpenAI n’est pas un JSON valide : ' + raw); }
return [{ json: menu }];
